3_real_world_example.code:
// Convention: Capitalize the first letter for Constructors
function User(name, age) {
  // 'this' refers to the new object being built
  this.name = name;
  this.age = age;
  this.isAdmin = false;
}

// We must use 'new' to trigger the factory behavior
const alice = new User('Alice', 25);
const bob = new User('Bob', 30);

console.log(alice.name); // 'Alice'
console.log(bob.isAdmin); // false

